const fs = require('fs');
const path = require('path');
const {
    Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
    HeadingLevel, AlignmentType, BorderStyle, WidthType, ShadingType,
    PageBreak, TabStopPosition, TabStopType
} = require('docx');

// ============ 配置 ============
const COLORS = {
    titleBlue: '1F4E79',
    bodyGray: '404040',
    negativeRed: 'C00000',
    positiveGreen: '2E7D32',
    white: 'FFFFFF',
    lightBlue: 'D6E4F0',
    lightGray: 'F2F2F2',
    mediumGray: 'E0E0E0',
    darkBlue: '1A3A5C',
};

const FONT = '微软雅黑';
const DATA_DIR = 'C:\\Users\\Administrator\\Desktop\\月度数据抓取';
const OUTPUT_DIR = 'C:\\Users\\Administrator\\Desktop\\运营复盘';

// ============ 数据读取 ============
function readJSON(filename) {
    const filepath = path.join(DATA_DIR, filename);
    if (!fs.existsSync(filepath)) {
        console.warn(`[警告] 未找到文件: ${filename}`);
        return null;
    }
    return JSON.parse(fs.readFileSync(filepath, 'utf8'));
}

const diagnoseData = readJSON('diagnose_data.json');
const buyerDetails = readJSON('buyer_details.json');
const fullWeekReport = readJSON('full_week_report.json');
const p4pProducts = readJSON('p4p_product_top30.json') || [];
const p4pRegions = readJSON('p4p_region_top30.json') || [];

// ============ 数据提取与计算 ============
const storeOverview = fullWeekReport?.values?.STORE_DATA_OVERVIEW || {};
const productOverview = fullWeekReport?.values?.PRODUCT_DATA_OVERVIEW || {};
const actionSuggestion = fullWeekReport?.values?.ACTION_SUGGESTION || {};
const diagnoseValues = diagnoseData?.values || {};
const weekDiagnose = diagnoseValues?.weekDiagnose?.[0]?.indicatorList || [];

const seClicks = storeOverview.seClkCntValue || 0;
const seImps = storeOverview.seImpsCntValue || 0;
const ctr = seImps > 0 ? ((seClicks / seImps) * 100).toFixed(2) : '0.00';

// Extract diagnose indicators
function getDiagnoseValue(name) {
    const item = weekDiagnose.find(d => d.name === name);
    return item ? { value: item.value, cycleCRC: item.cycleCRC || '', vsAvg: item.valueVsAvg || '' } : null;
}

const exposureData = getDiagnoseValue('全店曝光量');
const opportunityData = getDiagnoseValue('商机量');
const qualityProductData = getDiagnoseValue('4.5分品数量');

const busCount = actionSuggestion.busCount || 0;
const busAvg = actionSuggestion.busCountRivalAvg || 0;
const busGood = actionSuggestion.busCountRivalGood || 0;

const diagnoseSummary = diagnoseValues.diagnoseSummary || '';
const diagnoseTitle = diagnoseValues.diagnoseTitle || '';

const topCountries = buyerDetails?.top_10_countries || [];
const topKeywords = buyerDetails?.top_10_search_keywords || [];
const topCategories = productOverview?.top5Category || [];

// P4P totals
const p4pTotalClicks = p4pRegions.reduce((sum, r) => sum + parseInt(r.clicks || 0), 0);
const p4pTotalCost = p4pRegions.reduce((sum, r) => sum + parseFloat(r.cost || 0), 0);

// ============ 文档样式工具函数 ============

// 创建标题文本块（蓝色粗体大号）
function titleRun(text, size = 36, color = COLORS.titleBlue) {
    return new TextRun({ text, font: FONT, size, bold: true, color });
}

// 创建正文文本块
function bodyRun(text, size = 21, color = COLORS.bodyGray, options = {}) {
    return new TextRun({ text, font: FONT, size, color, ...options });
}

// 创建强调文本块（红色/绿色）
function emphasisRun(text, isNegative = true, size = 21) {
    return new TextRun({
        text,
        font: FONT,
        size,
        bold: true,
        color: isNegative ? COLORS.negativeRed : COLORS.positiveGreen,
    });
}

// 模块大标题（蓝色）
function moduleHeading(text, number) {
    return new Paragraph({
        children: [
            titleRun(`0${number} `, 28, COLORS.titleBlue),
            titleRun(text, 28, COLORS.titleBlue),
        ],
        spacing: { before: 400, after: 200 },
        border: {
            bottom: { style: BorderStyle.SINGLE, size: 6, color: COLORS.titleBlue, space: 4 },
        },
    });
}

// 子标题
function subHeading(text) {
    return new Paragraph({
        children: [titleRun(text, 24, COLORS.darkBlue)],
        spacing: { before: 280, after: 120 },
    });
}

// 小标题（三级）
function smallHeading(text) {
    return new Paragraph({
        children: [new TextRun({ text, font: FONT, size: 22, bold: true, color: COLORS.darkBlue })],
        spacing: { before: 200, after: 80 },
    });
}

// 正文段落
function bodyParagraph(text, options = {}) {
    return new Paragraph({
        children: [bodyRun(text, options.size || 21, options.color || COLORS.bodyGray, options.textOptions || {})],
        spacing: { before: options.before || 60, after: options.after || 60 },
        alignment: options.alignment || AlignmentType.LEFT,
        indent: options.indent || undefined,
    });
}

// 带强调的正文段落
function bodyWithEmphasis(textParts) {
    // textParts: [{ text, isEmphasis, isNegative }]
    const children = textParts.map(p =>
        p.isEmphasis
            ? emphasisRun(p.text, p.isNegative !== false, p.size || 21)
            : bodyRun(p.text, p.size || 21, p.color || COLORS.bodyGray)
    );
    return new Paragraph({
        children,
        spacing: { before: 60, after: 60 },
    });
}

// 空行
function spacer(height = 120) {
    return new Paragraph({ spacing: { before: height, after: 0 }, children: [] });
}

// 创建表格
function createTable(headers, rows, colWidths) {
    const headerRow = new TableRow({
        tableHeader: true,
        children: headers.map((h, i) =>
            new TableCell({
                width: { size: colWidths[i] || 1000, type: WidthType.DXA },
                shading: { type: ShadingType.SOLID, color: COLORS.titleBlue },
                verticalAlign: 'center',
                children: [
                    new Paragraph({
                        alignment: AlignmentType.CENTER,
                        spacing: { before: 40, after: 40 },
                        children: [new TextRun({ text: h, font: FONT, size: 20, bold: true, color: COLORS.white })],
                    }),
                ],
            })
        ),
    });

    const dataRows = rows.map((row, ri) =>
        new TableRow({
            children: row.map((cell, ci) =>
                new TableCell({
                    width: { size: colWidths[ci] || 1000, type: WidthType.DXA },
                    shading: ri % 2 === 1 ? { type: ShadingType.SOLID, color: COLORS.lightGray } : undefined,
                    verticalAlign: 'center',
                    children: [
                        new Paragraph({
                            alignment: AlignmentType.CENTER,
                            spacing: { before: 30, after: 30 },
                            children: [new TextRun({
